import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Empty.module.css';

export type EmptyRootProps = HTMLArkProps<'div'>;
export type EmptyIconProps = HTMLArkProps<'div'>;
export type EmptyContentProps = HTMLArkProps<'div'>;
export type EmptyTitleProps = HTMLArkProps<'h3'>;
export type EmptyDescriptionProps = HTMLArkProps<'div'>;
export type EmptyActionsProps = HTMLArkProps<'div'>;

const EmptyRoot = forwardRef<HTMLDivElement, EmptyRootProps>(function EmptyRoot(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="empty"
      data-part="root"
      data-slot="empty-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const EmptyIcon = forwardRef<HTMLDivElement, EmptyIconProps>(function EmptyIcon(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="empty"
      data-part="icon"
      data-slot="empty-icon"
      className={clsx(styles.icon, normalizeClassName(className))}
      {...props}
    />
  );
});

const EmptyContent = forwardRef<HTMLDivElement, EmptyContentProps>(function EmptyContent(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="empty"
      data-part="content"
      data-slot="empty-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const EmptyTitle = forwardRef<HTMLHeadingElement, EmptyTitleProps>(function EmptyTitle(
  { className, ...props },
  ref,
) {
  return (
    <ark.h3
      ref={ref}
      data-scope="empty"
      data-part="title"
      data-slot="empty-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const EmptyDescription = forwardRef<HTMLDivElement, EmptyDescriptionProps>(
  function EmptyDescription({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="empty"
        data-part="description"
        data-slot="empty-description"
        className={clsx(styles.description, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const EmptyActions = forwardRef<HTMLDivElement, EmptyActionsProps>(function EmptyActions(
  { className, ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      data-scope="empty"
      data-part="actions"
      data-slot="empty-actions"
      className={clsx(styles.actions, normalizeClassName(className))}
      {...props}
    />
  );
});

const Empty = Object.assign(EmptyRoot, {
  Root: EmptyRoot,
  Icon: EmptyIcon,
  Content: EmptyContent,
  Title: EmptyTitle,
  Description: EmptyDescription,
  Actions: EmptyActions,
});

export { Empty };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: grid;
    justify-items: center;
    width: 100%;
    min-width: 0;
    gap: var(--empty-gap, var(--spacing-4));
    padding: var(--empty-padding, var(--spacing-8));
    border: var(--empty-border-width, var(--border-width-sm)) solid
      var(--empty-border-color, var(--color-border));
    border-radius: var(--empty-radius, var(--radius-xl));
    background-color: var(
      --empty-bg,
      color-mix(in oklab, var(--color-card) 92%, var(--color-muted))
    );
    color: var(--empty-color, var(--color-card-foreground));
    box-shadow: var(--empty-shadow, none);
    text-align: center;
  }

  .icon {
    display: inline-flex;
    min-width: 0;
    align-items: center;
    justify-content: center;
    padding: var(--empty-icon-padding, var(--spacing-3));
    border-radius: var(--radius-full);
    background-color: var(--empty-icon-bg, var(--color-muted));
    color: var(--empty-icon-color, var(--color-muted-foreground));

    &:where(svg),
    & :where(svg) {
      width: var(--empty-icon-size, 1.5rem);
      height: var(--empty-icon-size, 1.5rem);
      flex-shrink: 0;
      pointer-events: none;
    }
  }

  .content {
    display: grid;
    min-width: 0;
    justify-items: center;
    gap: var(--empty-content-gap, var(--spacing-1));
    max-width: var(--empty-content-max-width, 28rem);
  }

  .title {
    margin: 0;
    min-width: 0;
    color: var(--empty-title-color, currentColor);
    font-size: var(--empty-title-font-size, var(--text-xl));
    font-weight: var(--empty-title-font-weight, var(--weight-semibold));
    line-height: var(--empty-title-line-height, var(--line-height-text-xl));
    overflow-wrap: anywhere;
  }

  .description {
    min-width: 0;
    color: var(--empty-description-color, var(--color-muted-foreground));
    font-size: var(--empty-description-font-size, var(--text-sm));
    line-height: var(--empty-description-line-height, var(--line-height-text-sm));
    overflow-wrap: anywhere;

    & > :first-child {
      margin-top: 0;
    }

    & > :last-child {
      margin-bottom: 0;
    }
  }

  .actions {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: center;
    gap: var(--empty-actions-gap, var(--spacing-2));
  }
}

export { Empty } from './Empty';
export type {
  EmptyActionsProps,
  EmptyContentProps,
  EmptyDescriptionProps,
  EmptyIconProps,
  EmptyRootProps,
  EmptyTitleProps,
} from './Empty';
